if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const body=$input.first().json.body||{};
if(body.auth_key!==$env.GDA_API_KEY_2026) return [{json:{error:'Unauthorized'}}];
return [{json:{action:body.action||'list'}}];

const rows=$input.all().map(i=>i.json);
const now=new Date();
const proposals=rows.map(r=>{const due=r.response_deadline?new Date(r.response_deadline):null;const daysLeft=due?Math.ceil((due-now)/(86400000)):null;return{...r,days_until_due:daysLeft,urgency:daysLeft!==null?(daysLeft<=7?'CRITICAL':daysLeft<=14?'HIGH':daysLeft<=30?'MEDIUM':'LOW'):'UNKNOWN'};});
return [{json:{status:'ok',count:proposals.length,proposals}}];
